const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// Fetch all data in parallel-ish manner
let courses = [];
let services = [];
let areas = [];
let combos = [];

try {
  const coursesResp = await this.helpers.httpRequest({ method: 'GET', url: CRM + '/api/courses', headers, json: true });
  courses = coursesResp.data || [];
  if (!Array.isArray(courses)) courses = [courses];
} catch(e) { courses = []; }

try {
  const servicesResp = await this.helpers.httpRequest({ method: 'GET', url: CRM + '/api/services', headers, json: true });
  services = servicesResp.data || [];
  if (!Array.isArray(services)) services = [services];
} catch(e) { services = []; }

try {
  const areasResp = await this.helpers.httpRequest({ method: 'GET', url: CRM + '/api/areas', headers, json: true });
  areas = areasResp.data || [];
  if (!Array.isArray(areas)) areas = [areas];
} catch(e) { areas = []; }

try {
  const combosResp = await this.helpers.httpRequest({ method: 'GET', url: CRM + '/api/combo/check', headers, json: true });
  combos = combosResp.data || [];
  if (!Array.isArray(combos)) combos = [combos];
} catch(e) { combos = []; }

// Fallback static data if CRM API is not available or returns empty list
if (courses.length === 0) {
  courses = [
    { id: 1, name: "Python Programming", seo_name: "python programming course", short_name: "Python" },
    { id: 2, name: "Data Analytics", seo_name: "data analytics training", short_name: "Data Analytics" },
    { id: 3, name: "MERN Stack Development", seo_name: "mern stack development course", short_name: "MERN" },
    { id: 4, name: "Android App Development", seo_name: "android app development course", short_name: "Android" },
    { id: 5, name: "Flutter UI/UX Development", seo_name: "flutter development training", short_name: "Flutter" },
    { id: 6, name: "Cyber Security & Ethical Hacking", seo_name: "cyber security training", short_name: "Cyber Security" },
    { id: 7, name: "BCA / BSCIT Coaching", seo_name: "bca bscit tuition coaching", short_name: "BCA/BSCIT" }
  ];
}

if (services.length === 0) {
  services = [
    { id: 101, name: "Local SEO Optimization", seo_name: "local seo optimization service", short_name: "Local SEO" },
    { id: 102, name: "Web Development Solutions", seo_name: "web development services", short_name: "Web Dev" },
    { id: 103, name: "Social Media Marketing", seo_name: "social media marketing service", short_name: "SMM" },
    { id: 104, name: "Graphic & UI/UX Design", seo_name: "graphic UI UX design service", short_name: "UI/UX" },
    { id: 105, name: "Lead Generation Campaign", seo_name: "lead generation marketing service", short_name: "Lead Gen" }
  ];
}

if (areas.length === 0) {
  areas = [
    { id: 201, area: "Vesu" },
    { id: 202, area: "Adajan" },
    { id: 203, area: "Varachha" },
    { id: 204, area: "Katargam" },
    { id: 205, area: "Pal" },
    { id: 206, area: "Piplod" },
    { id: 207, area: "Rander" }
  ];
}

return [{ json: { courses, services, areas, combos } }];

const { courses, services, areas, combos } = $input.first().json;

const now = new Date();
const sixtyDaysAgo = new Date(now);
sixtyDaysAgo.setDate(sixtyDaysAgo.getDate() - 60);

// Build blocked set (combos used within last 60 days)
const blockedSet = new Set();
for (const combo of combos) {
  if (combo.last_used_date) {
    const lastUsed = new Date(combo.last_used_date);
    if (lastUsed >= sixtyDaysAgo) {
      blockedSet.add(combo.brand + '_' + combo.content_type + '_' + combo.content_item_id + '_' + combo.area_id);
    }
  }
}

// Build valid Academy pool (course × area, not blocked)
const academyPool = [];
for (const course of courses) {
  for (const area of areas) {
    const key = 'extrabits_academy_course_' + course.id + '_' + area.id;
    if (!blockedSet.has(key)) {
      academyPool.push({
        brand: 'extrabits_academy',
        content_type: 'course',
        content_item_id: course.id,
        content_item_name: course.seo_name || course.course_name || course.name || '',
        short_name: course.short_name || '',
        area_id: area.id,
        area_name: area.area || '',
        seo_name: course.seo_name || ''
      });
    }
  }
}

// Build valid ExtraBits pool (service × area, not blocked)
const extrabitsPool = [];
for (const service of services) {
  for (const area of areas) {
    const key = 'extrabits_service_' + service.id + '_' + area.id;
    if (!blockedSet.has(key)) {
      extrabitsPool.push({
        brand: 'extrabits',
        content_type: 'service',
        content_item_id: service.id,
        content_item_name: service.seo_name || service.service_name || '',
        short_name: service.short_name || '',
        area_id: area.id,
        area_name: area.area || '',
        seo_name: service.seo_name || ''
      });
    }
  }
}

// Shuffle pools
const shuffle = (arr) => {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
};
shuffle(academyPool);
shuffle(extrabitsPool);

// Generate 7 suggestions with brand rotation
// Day 1 (Mon) = Academy, Day 2 (Tue) = ExtraBits, alternating
const monday = new Date(now);
monday.setDate(monday.getDate() + 1); // Sunday → Monday

const suggestions = [];
let academyIdx = 0;
let extrabitsIdx = 0;

for (let day = 0; day < 7; day++) {
  const date = new Date(monday);
  date.setDate(date.getDate() + day);
  const dateStr = date.toISOString().split('T')[0];
  const dayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

  const isAcademy = (day % 2 === 0); // 0,2,4,6 = Academy; 1,3,5 = ExtraBits
  let selected;

  if (isAcademy && academyIdx < academyPool.length) {
    selected = academyPool[academyIdx++];
  } else if (!isAcademy && extrabitsIdx < extrabitsPool.length) {
    selected = extrabitsPool[extrabitsIdx++];
  } else {
    // Fallback: use whatever pool has items
    if (academyIdx < academyPool.length) {
      selected = academyPool[academyIdx++];
    } else if (extrabitsIdx < extrabitsPool.length) {
      selected = extrabitsPool[extrabitsIdx++];
    } else {
      selected = { brand: 'N/A', content_item_name: 'No items available', area_name: '', seo_name: '' };
    }
  }

  // Generate keywords
  let primaryKw, secondaryKw;
  if (selected.brand === 'extrabits_academy') {
    primaryKw = 'best ' + selected.seo_name + ' near ' + selected.area_name + ' in surat';
    secondaryKw = 'best ' + selected.seo_name + ' institute in ' + selected.area_name + ' surat';
  } else {
    primaryKw = 'best ' + selected.seo_name + ' near ' + selected.area_name + ' in surat';
    secondaryKw = 'best ' + selected.seo_name + ' in ' + selected.area_name + ' surat';
  }

  suggestions.push({
    day: day + 1,
    day_name: dayNames[day],
    date: dateStr,
    brand: selected.brand,
    brand_label: selected.brand === 'extrabits_academy' ? 'Academy' : 'ExtraBits',
    content_type: selected.content_type || '',
    content_item_id: selected.content_item_id || '',
    content_item_name: selected.content_item_name || '',
    area_id: selected.area_id || '',
    area_name: selected.area_name || '',
    primary_keyword: primaryKw || '',
    secondary_keyword: secondaryKw || ''
  });
}

return [{ json: {
  monday_date: monday.toISOString().split('T')[0],
  suggestions,
  academy_pool_size: academyPool.length,
  extrabits_pool_size: extrabitsPool.length
} }];

const data = $input.first().json;
const suggestions = data.suggestions;

// Build Telegram message
let msg = '📅 Weekly Content Suggestions — Week of ' + data.monday_date + '\n';
msg += 'Available: ' + data.academy_pool_size + ' academy combos, ' + data.extrabits_pool_size + ' extrabits combos\n\n';

for (const s of suggestions) {
  msg += 'Day ' + s.day + ' (' + s.day_name + '): [' + s.brand_label + '] ' +
    s.content_item_name + ' | ' + s.area_name + '\n' +
    '  KW: ' + s.primary_keyword + '\n\n';
}

msg += '✅ Next step: Generate master captions for each row using the ChatGPT prompt in your system doc, then add to CRM Content Calendar with status = draft.';

// Send Telegram
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
  body: { chat_id: $env.TELEGRAM_CHAT_ID, text: msg },
  json: true
});

return [{ json: { ...data, _telegramSent: true } }];

const data = $input.first().json;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

let created = 0;
let failed = 0;

for (const s of data.suggestions) {
  if (!s.content_item_id || s.brand === 'N/A') {
    failed++;
    continue;
  }

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: CRM + '/api/content',
      body: {
        date: s.date,
        brand: s.brand,
        content_type: s.content_type,
        content_item_id: s.content_item_id,
        area_id: s.area_id,
        topic: s.content_item_name + ' in ' + s.area_name,
        primary_keyword: s.primary_keyword,
        secondary_keyword: s.secondary_keyword,
        status: 'draft'
      },
      headers: headers,
      json: true
    });
    created++;
  } catch(e) {
    failed++;
  }
}

return [{ json: { drafts_created: created, drafts_failed: failed } }];
